        -- Entradas desde el Filtro FIR
        entrada_dato    : in std_logic_vector(15 downto 0);
        entrada_valido  : in std_logic;
        -- Salida de vector de 16 magnitudes
        magnitud_dato   : out std_logic_vector(15 downto 0);
