            if RST = '1' then   
                buffer_muestras <= (others => (others => '0'));
                magnitudes      <= (others => (others => '0'));
                cnt_muestras    <= 0;
                cnt_bin         <= 0;
                cnt_n           <= 0;
                acum_real       <= (others => '0');
                acum_imag       <= (others => '0');
                estado          <= ACUMULANDO;
                magnitud_valido <= '0';
                magnitud_dato   <= (others => '0');
                espectro_listo  <= '0';
                magnitud_bin    <= 0;

            else
                -- Valores por defecto
                magnitud_valido <= '0';
                espectro_listo  <= '0';
                
                -- Maquina de estado 
                case estado is
                    -- Estado 1: ACUMULANDO: Espera las muestras del Filtro FIR
                    when ACUMULANDO =>
                        if entrada_valido   = '1' then  
                            buffer_muestras(cnt_muestras) <= signed(entrada_dato);
                            
                            if cnt_muestras = N - 1 then
                                -- Buffer lleno: Llenar DFT
                                cnt_muestras <= 0;
                                cnt_bin     <= 0;
                                cnt_n       <= 0;
                                acum_real   <= (others => '0');
                                acum_imag   <= (others => '0');
                                estado      <= CALCULANDO;
                            else
                                cnt_muestras    <= cnt_muestras + 1;
                            end if;
                        end if;
                    -- Estado 2: Calculando
                    when CALCULANDO =>
                        -- Multiplicar muestra por factor de rotacion   
                        prod_real   := buffer_muestras(cnt_n) * COS_TABLA(cnt_bin, cnt_n);
                        prod_img    := buffer_muestras(cnt_n) * SEN_TABLA(cnt_bin, cnt_n);

                        -- Acumular: Tomar los bits de parte fraccionaria Q1.15
                        acum_real   <= acum_real + resize(prod_real(30 downto 15), 40);
                        acum_imag   <= acum_imag + resize(prod_img(30 downto 15), 40);
                        
                        if cnt_n = N - 1 then
                            -- Terminamos las 64 muestras del binm
                            -- Calcular la magnitud con aproximaxion alpha-beta
                            if acum_real(39) = '1' then 
                                abs_real := unsigned(-acum_real(15 downto 0));
                            else
                                abs_real := unsigned(acum_real(15 downto 0));           
                            end if;

                            if acum_imag(39) = '1' then
                                abs_imag := unsigned(-acum_imag(15 downto 0));
                            else
                                abs_imag := unsigned(acum_imag(15 downto 0));
                            end if;

                            -- alpha-beta: mag = max * 0.375 * min
                            if abs_real >= abs_imag then
                                mag_alpha := abs_real;
                                mag_beta  := abs_imag;
                            else
                                mag_alpha := abs_imag;
                                mag_beta  := abs_real;
                            end if;


                            magnitudes(cnt_bin) <= mag_alpha + resize(mag_beta(15 downto 3) * to_unsigned(3, 13), 16);
                            
                            -- Pasamos al siguiente bin
                            cnt_n       <= 0;
                            acum_real   <= (others => '0');
                            acum_imag   <= (others => '0');
                
                            if cnt_bin = NUM_BINS -1 then
                                -- Todos los bins calculados -> enviar
                            cnt_bin <= 0;
                            estado  <= ENVIANDO;
                            else
                                cnt_bin <= cnt_bin + 1;
                            end if;

                        else
                            cnt_n <= cnt_n + 1;
                        end if;


                    -- Estado 3: Enviando las 16 magnitudes una por ciclo al modulo de matching euclidiano
                    when ENVIANDO =>
                        magnitud_dato   <= std_logic_vector(magnitudes(cnt_bin));
                        magnitud_bin    <= cnt_bin;
                        magnitud_valido <= '1';
                        
                        if cnt_bin  = NUM_BINS - 1 then
                            espectro_listo <= '1';
                            cnt_bin         <= 0;
                            estado          <= ACUMULANDO; -- Volver a acumular nuevas muestras
                        else
                            cnt_bin    <= cnt_bin + 1;
                        end if;
                end case;
            end if;
        end if;
    end process proc_fft;

end architecture rtl;